#ACESSING ELEMENTS IN A LIST & STRING USING INDEXING
Fruit="Mango"
print(Fruit[0])  #Accesses the first character of the string
print(Fruit[2])  #Accesses the third character of the string
#Negative Indexing
print(Fruit[-1]) #Accesses the last character of the string

Prime_num=[2,3,5,7,11]
print(Prime_num[0]) #Accesses the first element of the list
print(Prime_num[-2]) #Accesses the fourth element of the list
